class Solution:
    def removeInvalidParentheses(self, s: str) -> List[str]:
        def valid(t):
            bal = 0
            for c in t:
                if c == '(':
                    bal += 1
                elif c == ')':
                    bal -= 1
                    if bal < 0:
                        return False
            return bal == 0
        level, seen = {s}, {s}
        while level:
            good = [x for x in level if valid(x)]
            if good:
                return good
            nxt = set()
            for cur in level:
                for i, c in enumerate(cur):
                    if c not in '()':
                        continue
                    t = cur[:i] + cur[i + 1:]
                    if t not in seen:
                        seen.add(t)
                        nxt.add(t)
            level = nxt
        return []

