static int valid(const char* t) {
    int bal = 0;
    for (int i = 0; t[i]; i++) {
        if (t[i] == '(') bal++;
        else if (t[i] == ')') { if (--bal < 0) return 0; }
    }
    return bal == 0;
}
/* Full BFS needs dynamic string sets; use C++ for production. */
char** removeInvalidParentheses(char* s, int* retSize) {
    *retSize = 0;
    if (valid(s)) { char** r = malloc(sizeof(char*)); r[0] = strdup(s); *retSize = 1; return r; }
    return NULL;
}
